1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Customer = { yearsWithMHPCO: number };
3	type Scenario = { customer?: Customer; steps: Array<{ op: string; items: Array<Item> }> };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
7	const CURSED_SURCHARGE_RATE = 0.5;
8	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
9	const HIGH_ENCHANTMENT_THRESHOLD = 5;
10	const LOYALTY_DISCOUNT_RATE = 0.2;
11	const LOYALTY_YEARS_THRESHOLD = 2;
12	const FOLLOWUP_DISCOUNT_RATE = 0.15;
13	
14	const BASE_PREMIUMS: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: 25,
20	  moonstone: 25,
21	};
22	
23	function withFirstInsuranceSurcharge(basePremium: number): number {
24	  return basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
25	}
26	
27	function surchargeIf(condition: boolean, basePremium: number, rate: number): number {
28	  return condition ? basePremium * rate : 0;
29	}
30	
31	function quoteItem(item: Item): number {
32	  const basePremium = BASE_PREMIUMS[item.type];
33	  const isHighlyEnchanted = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
34	  const cursedSurcharge = surchargeIf(item.cursed === true, basePremium, CURSED_SURCHARGE_RATE);
35	  const highEnchantmentSurcharge = surchargeIf(
36	    isHighlyEnchanted,
37	    basePremium,
38	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
39	  );
40	  return withFirstInsuranceSurcharge(basePremium) + cursedSurcharge + highEnchantmentSurcharge;
41	}
42	
43	const COMPONENT_TYPES = ["rune", "moonstone"];
44	const BLOCK_OF_THREE_BASE = 60;
45	
46	function countByType(items: Array<Item>): Record<string, number> {
47	  const counts: Record<string, number> = {};
48	  for (const item of items) {
49	    counts[item.type] = (counts[item.type] ?? 0) + 1;
50	  }
51	  return counts;
52	}
53	
54	function isLoyalCustomer(customer: Customer | undefined): boolean {
55	  return (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_YEARS_THRESHOLD;
56	}
57	
58	function quoteItems(items: Array<Item>): { itemsPremium: number; sumOfBases: number } {
59	  const counts = countByType(items);
60	  let itemsPremium = 0;
61	  let sumOfBases = 0;
62	  const bundledTypes = new Set<string>();
63	
64	  for (const componentType of COMPONENT_TYPES) {
65	    if (counts[componentType] === 3) {
66	      itemsPremium += withFirstInsuranceSurcharge(BLOCK_OF_THREE_BASE);
67	      sumOfBases += BLOCK_OF_THREE_BASE;
68	      bundledTypes.add(componentType);
69	    }
70	  }
71	
72	  for (const item of items) {
73	    if (bundledTypes.has(item.type)) continue;
74	    itemsPremium += quoteItem(item);
75	    sumOfBases += BASE_PREMIUMS[item.type];
76	  }
77	
78	  return { itemsPremium, sumOfBases };
79	}
80	
81	export function processScenario(scenario: unknown): { results: Array<{ premium?: number }> } {
82	  const { customer, steps } = scenario as Scenario;
83	  const results: Array<{ premium?: number }> = [];
84	
85	  for (const [stepIndex, step] of steps.entries()) {
86	    let { itemsPremium, sumOfBases } = quoteItems(step.items);
87	
88	    if (isLoyalCustomer(customer)) {
89	      itemsPremium -= sumOfBases * LOYALTY_DISCOUNT_RATE;
90	    }
91	
92	    const isFollowUp = stepIndex >= 1;
93	    if (isFollowUp) {
94	      itemsPremium -= sumOfBases * FOLLOWUP_DISCOUNT_RATE;
95	    }
96	
97	    const premium = Math.ceil(itemsPremium + PROCESSING_FEE);
98	    results.push({ premium });
99	  }
100	
101	  return { results };
102	}
